        ];

        // 6. Loop and Insert
        $count = 0;
        foreach ($usersData as $row) {
            $legacyId = $row[0];

            // Check the dictionary for types, or provide empty array
            $assignedTypes = $userTypeLookup[$legacyId] ?? [];

            User::create([
                'id'             => $legacyId,
                'first_name'     => $row[1],
                'last_name'      => $row[2],
                'email'          => $row[3],
                'country_id'     => $row[4],
                'region_id'      => $row[5],
                'city'           => $row[6],
                'user_code'      => $row[7],
                'password'       => $row[8],
                'status_id'      => $row[9],
                'date_created'   => $row[10],
                'user_last_log'  => $row[11],
                'avatar_url'     => $row[12],
                'email_verified' => (bool)$row[13],
                'timestamp'      => $row[14],
                'user_type_ids'  => $assignedTypes // INJECTED!
            ]);
            $count++;
        }

        $messages[] = "Successfully imported $count users with their type mappings.";
    } catch (\Throwable $e) {
        $messages[] = 'Users table error: ' . $e->getMessage();
    } finally {
        Capsule::schema()->enableForeignKeyConstraints();
    }

    return $messages;
}
